# Deploy a cost workbook via ARM template
WORKBOOK_TEMPLATE='{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
  "contentVersion": "1.0.0.0",
  "resources": [{
    "type": "microsoft.insights/workbooks",
    "apiVersion": "2022-04-01",
    "name": "[guid(resourceGroup().id, parameters('"'"'workbookName'"'"'))]",
    "location": "[resourceGroup().location]",
    "kind": "shared",
    "properties": {
      "displayName": "[parameters('"'"'workbookName'"'"')]",
      "serializedData": "..."
    }
  }]
}'

# In practice, export the workbook JSON from the portal and deploy via
az deployment group create \
  --resource-group rg-monitoring \
  --template-file workbook-cost-centre.json
